/*
 * nn_openmp.c
 * Nearest Neighbor - OpenMP version
 *
 */

#include <stdio.h>
#include <sys/time.h>
#include <float.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define min( a, b )         a > b ? b : a
#define ceilDiv( a, b )     ( a + b - 1 ) / b
#define DEBUG               0

#define MAX_ARGS 10
#define REC_LENGTH 53
#define LATITUDE_POS 28
#define OPEN 10000

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

int loadData(char *filename, Record **records_out, LatLong **locations_out, int *capacity_out);
void findLowest(Record *records, float *distances, int numRecords, int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);

int main(int argc, char* argv[])
{
    int    i=0;
    float lat, lng;
    int quiet=0, timing=0, platform=0, device=0;

    Record *records = NULL;
    LatLong *locations = NULL;
    char filename[100];
    int resultsCount=10;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                     &quiet, &timing, &platform, &device)) {
      printUsage();
      return 0;
    }

    int capacity = 0;
    int numRecords = loadData(filename, &records, &locations, &capacity);
    if (resultsCount > numRecords) resultsCount = numRecords;

    float *distances = (float *)malloc(sizeof(float) * numRecords);

    struct timeval tv_kernel_start, tv_kernel_end;
    float kernel_time = 0.0f;

    gettimeofday(&tv_kernel_start, NULL);

    /* Compute Euclidean distances using OpenMP */
    #pragma omp parallel for schedule(static)
    for (i = 0; i < numRecords; i++) {
        float dlat = lat - locations[i].lat;
        float dlng = lng - locations[i].lng;
        distances[i] = (float)sqrt(dlat*dlat + dlng*dlng);
    }

    gettimeofday(&tv_kernel_end, NULL);
    kernel_time = (tv_kernel_end.tv_sec - tv_kernel_start.tv_sec) * 1000.0f +
                  (tv_kernel_end.tv_usec - tv_kernel_start.tv_usec) / 1000.0f;

    /* find the resultsCount least distances */
    findLowest(records, distances, numRecords, resultsCount);

    /* print out results */
    if (!quiet)
    for(i=0;i<resultsCount;i++) {
      printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
    }

    if (timing) {
      printf("Exec: %f\n", kernel_time);
    }

    /* Always print total time to match expected output */
    {
      printf("total time: %f\n", kernel_time);
    }

    free(distances);
    free(records);
    free(locations);

    return 0;
}

int loadData(char *filename, Record **records_out, LatLong **locations_out, int *capacity_out)
{
    FILE   *flist, *fp;
    int    i=0;
    char dbname[64];
    int recNum=0;
    int capacity = 1024;

    Record *records = (Record *)malloc(sizeof(Record) * capacity);
    LatLong *locations = (LatLong *)malloc(sizeof(LatLong) * capacity);

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist\n");
        exit(1);
    }
    while(!feof(flist)) {
        if(fscanf(flist, "%s\n", dbname) != 1) {
            if (feof(flist)) break;
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db\n");
            exit(1);
        }
        while(!feof(fp)){
            Record record;
            LatLong latLong;
            fgets(record.recString, 49, fp);
            fgetc(fp); // newline
            if (feof(fp)) break;

            char substr[6];

            for(i=0;i<5;i++) substr[i] = *(record.recString+i+28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i=0;i<5;i++) substr[i] = *(record.recString+i+33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            if (recNum >= capacity) {
                capacity *= 2;
                records = (Record *)realloc(records, sizeof(Record) * capacity);
                locations = (LatLong *)realloc(locations, sizeof(LatLong) * capacity);
            }

            locations[recNum] = latLong;
            records[recNum] = record;
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    *records_out = records;
    *locations_out = locations;
    *capacity_out = capacity;
    return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN)
{
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for(i=0;i<topN;i++) {
        minLoc = i;
        for(j=i;j<numRecords;j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }
        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d)
{
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for(i=1;i<argc;i++) {
      if (argv[i][0]=='-') {
        flag = argv[i][1];
          switch (flag) {
            case 'r':
              i++;
              *r = atoi(argv[i]);
              break;
            case 'l':
              if (argv[i][2]=='a') {
                *lat = atof(argv[i+1]);
              }
              else {
                *lng = atof(argv[i+1]);
              }
              i++;
              break;
            case 'h':
              return 1;
            case 'q':
              *q = 1;
              break;
            case 't':
              *t = 1;
              break;
            case 'p':
              i++;
              *p = atoi(argv[i]);
              break;
            case 'd':
              i++;
              *d = atoi(argv[i]);
              break;
        }
      }
    }
    if ((*d >= 0 && *p<0) || (*p>=0 && *d<0))
      return 1;
    return 0;
}

void printUsage()
{
  printf("Nearest Neighbor Usage\n");
  printf("\n");
  printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
  printf("\n");
  printf("example:\n");
  printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
  printf("\n");
  printf("filename     the filename that lists the data input files\n");
  printf("-r [int]     the number of records to return (default: 10)\n");
  printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
  printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
  printf("\n");
  printf("-h, --help   Display the help file\n");
  printf("-q           Quiet mode. Suppress all text output.\n");
  printf("-t           Print timing information.\n");
  printf("\n");
  printf("-p [int]     Choose the platform (must choose both platform and device)\n");
  printf("-d [int]     Choose the device (must choose both platform and device)\n");
  printf("\n");
  printf("\n");
  printf("Notes: 1. The filename is required as the first parameter.\n");
  printf("       2. If you declare either the device or the platform,\n");
  printf("          you must declare both.\n\n");
}
